create table dirkspzm32.aps_planparameter (
    id                           varchar2(50 char) default 'Standard' not null enable,
    name                         varchar2(50 char) default 'Standard',
    dauerstabilerzeitraum        number(*, 0) default 0,
    terminierung                 number(*, 0) default 1,
    planungstypen                number(*, 0) default 3,
    zfparamruesten               number(*, 0) default 100,
    zfparampersonal              number(*, 0) default 100,
    zfparamfertigung             number(*, 0) default 100,
    zfparamkapitalbindung        number(*, 0) default 100,
    zfparamdlz                   number(*, 0) default 100,
    zfparamverzug                number(*, 0) default 100,
    zfparamkapazitaetsauslastung number(*, 0) default 0,
    anzahloptimierungen          number(*, 0) default 10,
    anzahlergebnisse             number(*, 0) default 3,
    planungsart                  number(*, 0) default 1,
    losgroessenoptimierung       number(*, 0) default 1,
    chk_lgr_eigenprod            number(*, 0) default 1,
    chk_lgr_zukauf               number(*, 0) default 1,
    mrp_gen_fa_auftrag           number(*, 0) default 1
);

alter table dirkspzm32.aps_planparameter
    add constraint pk_aps_planparameter primary key ( id )
        using index enable;


